var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"후….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_03"},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"괴, 굉장하다…!","JPN":"す、すごい……！","ENG":"That was amazing...!","TWN":"真，真是難以置信……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤였지? 빨리 레이더 확인해 줘.","JPN":"サシャ、だっけ。早くレーダーを確認して。","ENG":"Sasha, right? Check the radar for me.","TWN":"莎夏，對吧？再試試檢查下雷達。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아, 알았어!","JPN":"わ、わかった！","ENG":"Oh, okay!","TWN":"喔，知道了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"잠잠해. 반응이 완전히 사라진 것 같아.","JPN":"何もない。反応はもう消えたみたい。","ENG":"It's silent. The signal's completely gone.","TWN":"安靜了。反應好像完全消失了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"침식체는 언제 어디서든 다시 나타날 수 있으니까 서둘러야 할 거야.","JPN":"侵食体はいつどこから現れるかわからない。急いでこの場を去ったほうがいい。","ENG":"We have to hurry since the C.O.s can appear out of nowhere at any time.","TWN":"侵蝕體隨時可能再次出現，我們得抓緊時間。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이번엔 안 도망가?","JPN":"今度は、逃げないの？","ENG":"Aren't you going to run away?","TWN":"你不準備離開了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아까 목숨 걸고 날 구해주려 했었지?","JPN":"さっき命をかけて私を守ろうとしたでしょう。","ENG":"You tried to save me by risking your life, right?","TWN":"你剛剛拼了命想救我吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그 보답이야.","JPN":"だからそのお礼。","ENG":"I'm just repaying the favor.","TWN":"這是報答。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응… 구해줘서 정말 고마워.","JPN":"うん……助けてくれて本当にありがとう。","ENG":"Okay... Thanks for saving me.","TWN":"嗯……很感謝你救了我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아아…! 근데 수레가 다 망가져 버렸네.","JPN":"ああ……！　でも荷車が壊れちゃった。","ENG":"No...! My cart's all banged up.","TWN":"啊啊……！不過車子壞了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"다시 고치려면 시간이 필요한데, 오늘은 그냥 빈손으로 돌아갈 수밖에 없나….","JPN":"直すには時間がかかるな……今日は手ぶらで帰るしかないかぁ……","ENG":"It'll take some time to fix it. Guess I'm going back empty-handed today...","TWN":"修好要花不少時間，看來今天只能空手而歸了……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그 고물들이 꼭 필요한 물건이야?","JPN":"その古鉄がそんなに大事？","ENG":"Do you really need all this junk?","TWN":"那些破銅爛鐵是必需品嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응. 이것들을 쓸만한 물건으로 바꿔서 돈을 벌고 있거든.","JPN":"うん、私はこれを使えそうな物にして、それを売って稼いでいるの。","ENG":"I do. I turn them into useful items and sell them for money.","TWN":"嗯。我靠把這些東西變成有用的物品來賺錢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"많이 궁핍한 마을인가 보네.","JPN":"ずいぶんと生活が厳しい村のようね。","ENG":"Guess your village is pretty poor.","TWN":"看來是個很窮的村子。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그, 그런 뜻이 아냐!","JPN":"ち、違うよ！","ENG":"Th-that's not what I meant!","TWN":"不，不是那個意思！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마을도 나한테 이것저것 많이 도와줘서 보답하는 것뿐이야.","JPN":"村の人たちには色々と助けてもらったから、私もお礼がしたいだけ。","ENG":"The village helped me a lot and I'm just giving back what I can.","TWN":"村子裡的人也幫了我很多忙，我只是回報他們而已。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"사실 고물 수집도 항상 민병단과 함께 했었는데, 오늘은 내가 멋대로 나온 거거든.","JPN":"実は古鉄集めだっていつもは民兵団と一緒にやってたのに、今日は勝手に一人で出てきたの。","ENG":"Actually, I always collected the junk with the militia, but I came out alone today.","TWN":"其實我平時都是和民兵團一起收集破銅爛鐵的，今天是我擅自跑出來。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"에헤헤… 솔직히 나도 이제 침식체랑 붙어볼 만하다 생각했는데 아니었네.","JPN":"えへへ……正直なところ、私も侵食体とやり合えるぐらいには成長したかな、と思ってたけど。まだまだだったね。","ENG":"Hehehe... I really thought that I could take on a C.O. now. Guess I was wrong.","TWN":"嘿嘿……說實話，我還以為自己已經能對付侵蝕體了，看來還是不行啊……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그 수레, 고치는데 얼마나 걸려?","JPN":"その荷車、直すにはどれぐらいかかりそう？","ENG":"How long will it take to fix that cart?","TWN":"那輛車修好要多久？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응? 한 30분 정도면 될 걸?","JPN":"ん？　30分ぐらいかな？","ENG":"Hmm? About thirty minutes or so?","TWN":"嗯？大概30分鐘左右吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"레이더 이리 줘. 내가 망을 보고 있을 테니까 고치고 있어.","JPN":"レーダーを渡して。私が見張りをするから、その間に直して。","ENG":"Give me the radar. I'll stand guard while you fix it.","TWN":"把雷達給我。我來站哨，你去修吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"저, 정말 도와주는 거야?","JPN":"ほ、本当に手伝ってくれるの？","ENG":"Y-you're really going to help me?","TWN":"真，真的要來幫忙嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"역시 내가 사람 보는 눈은 짱이라니까!","JPN":"やっぱり私ってば、人を見る目があるんだよね～！","ENG":"I knew I had a good eye for people!","TWN":"果然，我看人的眼光還是蠻準的嘛！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"틱틱대긴 해도, 넌 좋은 녀석이야!","JPN":"ちょっと不愛想だけど、あなたは優しい子だよ！","ENG":"You complain a bit, but you're a good person!","TWN":"雖然你有點愛抱怨，但你是個好人！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"다 고쳤어! 하는 김에 고물도 고쳐놨고, 이제 마브카만 실으면 되겠다!","JPN":"終わった！　ついでに古鉄も直しといたし、あとはマブカを乗せるだけだね！","ENG":"All done! I even fixed the junk while I was at it. Now, I can load Mavka on the cart!","TWN":"全修好了！順便把破銅爛鐵也修好了，現在只要裝上瑪卡就行了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……하필 이럴 때 또 못 움직이게 되다니.","JPN":"……よりにもよってこんな時に、また動けなくなるなんて。","ENG":"...Can't believe I stopped moving again.","TWN":"……偏偏在這種時候又動不了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"신경 쓰지 마. 덕분에 수레도 고쳤고, 고물도 챙길 수 있었잖아.","JPN":"気にしないで。おかげで荷車も直ったし、古鉄も持ち帰れるようになったんだから。","ENG":"Don't worry. I fixed the cart thanks to you, and I get to keep all the junk.","TWN":"別在意這個。多虧了你，車修好了，破銅爛鐵也保了下來。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그럼 다시 가볼까? 영차!","JPN":"じゃあ、行ってみよう！　よいしょっと！","ENG":"Shall we get going? Hup!","TWN":"那我們繼續上路吧？嘿咻！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_WOOD"}]`);export{e as default};